CREATE OR REPLACE VIEW view_tge_dep_coll_dep (deposit_account_no, seq_no, operate_date, item_type, deposit_amount, deposit_balance, sign_flag, item_type_desc, value_amount) AS SELECT sc_dep_m_creditor_item.deposit_account_no,
sc_dep_m_creditor_item.seq_no,   
sc_dep_m_creditor_item.operate_date,   
sc_dep_m_creditor_item.item_type,   
sc_dep_m_creditor_item.deposit_balance AS deposit_amount,   
sc_dep_m_creditor_item.total_balance AS deposit_balance,   


sc_dep_m_ucf_dep_item_type.sign_flag,   
sc_dep_m_ucf_dep_item_type.deposit_item_description AS item_type_desc ,

0 as value_amount

FROM sc_dep_m_creditor_item,   
         sc_dep_m_ucf_dep_item_type
WHERE  1=1
and sc_dep_m_creditor_item.item_type = sc_dep_m_ucf_dep_item_type.deposit_item_type
--and sc_dep_m_creditor_item.deposit_account_no = 'depno'
--and  sc_dep_m_creditor_item.operate_date >= 'dd/mm/yyyy'
ORDER BY sc_dep_m_creditor_item.seq_no;

